const user = { name: 'Alice', avatarUrl: '/alice.jpg' };
const MAX_LENGTH = 100;

<img src={user.avatarUrl} alt={user.name} />
<input maxLength={MAX_LENGTH} />
<p title={`${user.name}'s profile`}>{user.name}</p>

// ✗ HTML attribute — not valid in JSX
<div class="card">...</div>

// ✔ JSX attribute
<div className="card">...</div>

function Button({ variant = 'primary', size = 'md' }) {
  return (
    <button className={`btn btn-${variant} btn-${size}`}>
      Click me
    </button>
  );
}

// Usage:
<Button variant="danger" size="lg" />
// Renders: className="btn btn-danger btn-lg"

function Tab({ label, isActive, onClick }) {
  return (
    <button
      className={`tab ${isActive ? 'tab-active' : ''}`}
      onClick={onClick}
    >
      {label}
    </button>
  );
}

import clsx from 'clsx';

function Button({ variant, disabled, loading }) {
  return (
    <button
      className={clsx(
        'btn',
        `btn-${variant}`,
        disabled && 'btn-disabled',
        loading && 'btn-loading',
      )}
      disabled={disabled || loading}
    >
      {loading ? 'Loading...' : 'Submit'}
    </button>
  );
}

// ✗ HTML string — not valid in JSX
<div style="color: red; font-size: 16px; background-color: #fff">

// ✔ JavaScript object
<div style={{
  color: 'red',
  fontSize: 16,          // number → '16px' automatically
  backgroundColor: '#fff', // hyphen → camelCase
}}>

function ProgressBar({ percent }) {
  return (
    <div className="progress-track">
      <div
        className="progress-fill"
        style={{
          width: `${percent}%`,
          backgroundColor: percent === 100 ? '#22c55e' : '#3b82f6',
        }}
      />
    </div>
  );
}

// ✗ HTML attribute — works but triggers a warning
<label for="email">Email</label>

// ✔ JSX attribute
<label htmlFor="email">Email</label>
<input id="email" type="email" />

// ✗ HTML-style string — not valid in JSX
<button onclick="handleClick()">Submit</button>

// ✔ Function reference (calls handleClick when clicked)
<button onClick={handleClick}>Submit</button>

// ✔ Arrow function (inline)
<button onClick={() => setCount(c => c + 1)}>+</button>

// ✔ Passing arguments via arrow function
<button onClick={() => handleDelete(item.id)}>Delete</button>

// Input wrapper — forwards all HTML input attributes
function Input({ label, error, className, ...inputProps }) {
  return (
    <div className="field">
      <label>{label}</label>
      <input
        {...inputProps}   // passes type, placeholder, value, onChange, etc.
        className={clsx('input', error && 'input-error', className)}
      />
      {error && <p className="error-msg">{error}</p>}
    </div>
  );
}

// Caller
<Input
  label="Email"
  type="email"
  value={email}
  onChange={e => setEmail(e.target.value)}
  placeholder="alice@example.com"
  required
  error={emailError}
/>

// Button.module.css
// .btn { padding: 8px 16px; }
// .btn-primary { background: #3b82f6; }
// .btn-danger  { background: #ef4444; }

import styles from './Button.module.css';

function Button({ variant = 'primary', children }) {
  return (
    <button className={`${styles.btn} ${styles[`btn-${variant}`]}`}>
      {children}
    </button>
  );
}

import clsx from 'clsx';

function Badge({ variant = 'gray', children }) {
  return (
    <span
      className={clsx(
        'inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium',
        variant === 'green'  && 'bg-green-100 text-green-800',
        variant === 'red'    && 'bg-red-100 text-red-800',
        variant === 'blue'   && 'bg-blue-100 text-blue-800',
        variant === 'gray'   && 'bg-gray-100 text-gray-800',
      )}
    >
      {children}
    </span>
  );
}

// CSS custom properties via style — drives CSS-side animations
function Spinner({ speed = 1 }) {
  return (
    <div
      className="spinner"
      style={{ '--spin-duration': `${speed}s` }}
    />
  );
}

// .spinner { animation: spin var(--spin-duration) linear infinite; }

import { useState } from 'react';

function SearchBox() {
  const [query, setQuery] = useState('');

  return (
    <input
      type="text"
      value={query}                          // controlled by state
      onChange={e => setQuery(e.target.value)} // updates state on each keystroke
      placeholder="Search..."
      className="search-input"
    />
  );
}

// Warning: A component is contentEditable and contains children managed by React.
// Use suppressContentEditableWarning only if you intentionally manage it yourself.
<div
  contentEditable
  suppressContentEditableWarning
  onInput={e => setText(e.currentTarget.textContent)}
>
  {initialText}
</div>

// ✗ camelCase unknown prop — React warns and drops it
<div myCustomProp="value" />

// ✔ kebab-case data attribute — passes through to DOM
<div data-custom-prop="value" />

// When spreading, destructure out non-DOM props first
function Tooltip({ tooltip, children, ...rest }) {
  return (
    <div title={tooltip} {...rest}> {/* rest contains only valid DOM attrs */}
      {children}
    </div>
  );
}

// Uncontrolled: initial value only — user can type freely, React doesn't track
<input defaultValue="Alice" />

// Controlled: React owns the value — must pair with onChange
<input value={name} onChange={e => setName(e.target.value)} />

import clsx from 'clsx';

function ArticleCard({ article, isHighlighted, onBookmark }) {
  const { id, title, author, readingTime, coverUrl, isBookmarked } = article;

  const cardClass = clsx(
    'article-card',
    isHighlighted && 'article-card--highlighted',
    isBookmarked && 'article-card--saved',
  );

  const coverStyle = {
    backgroundImage: `url(${coverUrl})`,
    height: isHighlighted ? 240 : 160,  // bigger image for featured articles
  };

  return (
    <article
      className={cardClass}
      data-article-id={id}
      aria-label={title}
    >
      <div className="cover" style={coverStyle} />

      <div className="body">
        <h2 className="title">{title}</h2>
        <p className="meta">{author} · {readingTime} min read</p>
      </div>

      <button
        className={clsx('bookmark-btn', isBookmarked && 'bookmark-btn--active')}
        onClick={() => onBookmark(id)}
        aria-label={isBookmarked ? 'Remove bookmark' : 'Add bookmark'}
        aria-pressed={isBookmarked}
      >
        {isBookmarked ? '★' : '☆'}
      </button>
    </article>
  );
}
